class InventorySystem:
    def __init__(self):
        self.items: Dict[str, Item] = {}
        self.owners: Dict[str, str] = {}  # item_id -> player_id
        self.players: Dict[str, Player] = {}
        self.player_locks: Dict[str, asyncio.Lock] = {}
        self.item_locks: Dict[str, asyncio.Lock] = {}
        self._global_lock = asyncio.Lock()

    async def ensure_player(self, player_id: str, name: str) -> Player:
        async with self._global_lock:
            p = self.players.get(player_id)
            if p is None:
                p = Player(player_id=player_id, name=name)
                self.players[player_id] = p
            else:
                p.name = name or p.name
            if player_id not in self.player_locks:
                self.player_locks[player_id] = asyncio.Lock()
            return p

    async def bind_ws(self, player_id: str, ws: WebSocketServerProtocol) -> None:
        async with self._global_lock:
            p = self.players[player_id]
            p.ws = ws

    async def unbind_ws(self, player_id: str, ws: WebSocketServerProtocol) -> None:
        async with self._global_lock:
            p = self.players.get(player_id)
            if p and p.ws is ws:
                p.ws = None

    def _get_item_lock(self, item_id: str) -> asyncio.Lock:
        lock = self.item_locks.get(item_id)
        if lock is None:
            lock = asyncio.Lock()
            self.item_locks[item_id] = lock
        return lock

    def _get_player_lock(self, player_id: str) -> asyncio.Lock:
        lock = self.player_locks.get(player_id)
        if lock is None:
            lock = asyncio.Lock()
            self.player_locks[player_id] = lock
        return lock

    async def create_item_for_player(self, owner_id: str, template: str, meta: Optional[Dict[str, Any]] = None) -> Item:
        item_id = secrets.token_urlsafe(10)
        item = Item(item_id=item_id, template=template, meta=meta or {})
        async with self._global_lock:
            self.items[item_id] = item
            self.owners[item_id] = owner_id
            self.players[owner_id].inventory.add(item_id)
            self._get_item_lock(item_id)
        return item

    async def get_inventory_snapshot(self, player_id: str) -> List[Dict[str, Any]]:
        p = self.players[player_id]
        async with self._get_player_lock(player_id):
            item_ids = list(p.inventory)
        out = []
        for iid in item_ids:
            it = self.items.get(iid)
            if it is None:
                continue
            out.append({"item_id": it.item_id, "template": it.template, "meta": it.meta})
        return out

    async def transfer_item(self, from_id: str, to_id: str, item_id: str) -> Tuple[bool, str]:
        if from_id == to_id:
            return False, "cannot_transfer_to_self"
        if item_id not in self.items:
            return False, "unknown_item"
        if from_id not in self.players or to_id not in self.players:
            return False, "unknown_player"

        # Lock ordering to avoid deadlocks: item lock, then player locks ordered by id
        item_lock = self._get_item_lock(item_id)
        a, b = sorted([from_id, to_id])
        lock_a = self._get_player_lock(a)
        lock_b = self._get_player_lock(b)

        async with item_lock:
            async with lock_a:
                async with lock_b:
                    owner = self.owners.get(item_id)
                    if owner != from_id:
                        return False, "not_item_owner"
                    pf = self.players[from_id]
                    pt = self.players[to_id]
                    if item_id not in pf.inventory:
                        return False, "item_not_in_inventory"
                    pf.inventory.remove(item_id)
                    pt.inventory.add(item_id)
                    self.owners[item_id] = to_id
                    return True, "ok"

    async def batch_trade(self, from_id: str, to_id: str, item_ids: List[str]) -> Tuple[bool, str, List[str], List[Tuple[str, str]]]:
        if from_id == to_id:
            return False, "cannot_transfer_to_self", [], []
        if from_id not in self.players or to_id not in self.players:
            return False, "unknown_player", [], []

        item_ids = [iid for iid in item_ids if isinstance(iid, str)]
        if not item_ids:
            return False, "no_items", [], []

        # To support atomic-like behavior, lock all items in sorted order, then player locks.
        item_locks = [self._get_item_lock(iid) for iid in sorted(set(item_ids))]
        a, b = sorted([from_id, to_id])
        lock_a = self._get_player_lock(a)
        lock_b = self._get_player_lock(b)

        acquired: List[asyncio.Lock] = []
        try:
            for l in item_locks:
                await l.acquire()
                acquired.append(l)
            await lock_a.acquire()
            acquired.append(lock_a)
            await lock_b.acquire()
            acquired.append(lock_b)

            pf = self.players[from_id]
            pt = self.players[to_id]

            moved: List[str] = []
            failed: List[Tuple[str, str]] = []

            for iid in item_ids:
                if iid not in self.items:
                    failed.append((iid, "unknown_item"))
                    continue
                owner = self.owners.get(iid)
                if owner != from_id:
                    failed.append((iid, "not_item_owner"))
                    continue
                if iid not in pf.inventory:
                    failed.append((iid, "item_not_in_inventory"))
                    continue

                pf.inventory.remove(iid)
                pt.inventory.add(iid)
                self.owners[iid] = to_id
                moved.append(iid)

            if not moved:
                return False, "no_items_moved", moved, failed
            return True, "ok", moved, failed
        finally:
            for l in reversed(acquired):
                try:
                    l.release()
                except RuntimeError:
                    pass


class GameServer:
    def __init__(self, host: str = "0.0.0.0", port: int = 8765):
        self.host = host
        self.port = port
        self.inv = InventorySystem()
        self.connections: Dict[WebSocketServerProtocol, str] = {}
        self._conn_lock = asyncio.Lock()

    async def send(self, ws: WebSocketServerProtocol, msg: Dict[str, Any]) -> None:
        try:
            await ws.send(jdump(msg))
        except Exception:
            pass

    async def broadcast_to_player(self, player_id: str, msg: Dict[str, Any]) -> None:
        p = self.inv.players.get(player_id)
        if p and p.ws:
            await self.send(p.ws, msg)

    async def handle_login(self, ws: WebSocketServerProtocol, data: Dict[str, Any]) -> None:
        player_id = str(data.get("player_id") or "")
        name = str(data.get("name") or player_id)
        if not player_id:
            await self.send(ws, {"type": "login_result", "ok": False, "error": "missing_player_id"})
            return

        p = await self.inv.ensure_player(player_id, name)
        await self.inv.bind_ws(player_id, ws)

        async with self._conn_lock:
            self.connections[ws] = player_id

        inv = await self.inv.get_inventory_snapshot(player_id)
        await self.send(ws, {"type": "login_result", "ok": True, "player_id": player_id, "name": p.name, "inventory": inv})

    async def handle_inventory_get(self, ws: WebSocketServerProtocol, player_id: str, data: Dict[str, Any]) -> None:
        inv = await self.inv.get_inventory_snapshot(player_id)
        await self.send(ws, {"type": "inventory", "ok": True, "inventory": inv})

    async def handle_spawn_item(self, ws: WebSocketServerProtocol, player_id: str, data: Dict[str, Any]) -> None:
        template = str(data.get("template") or "")
        if not template:
            await self.send(ws, {"type": "spawn_item_result", "ok": False, "error": "missing_template"})
            return
        meta = data.get("meta")
        if meta is not None and not isinstance(meta, dict):
            meta = {}
        item = await self.inv.create_item_for_player(player_id, template, meta)
        await self.send(ws, {"type": "spawn_item_result", "ok": True, "item": {"item_id": item.item_id, "template": item.template, "meta": item.meta}})
        await self.broadcast_to_player(player_id, {"type": "inventory_update", "reason": "spawn", "item_id": item.item_id})

    async def handle_trade(self, ws: WebSocketServerProtocol, from_id: str, data: Dict[str, Any]) -> None:
        to_id = str(data.get("to") or "")
        item_id = str(data.get("item_id") or "")
        request_id = data.get("request_id")
        if not to_id or not item_id:
            await self.send(ws, {"type": "trade_result", "ok": False, "error": "missing_to_or_item_id", "request_id": request_id})
            return

        ok, reason = await self.inv.transfer_item(from_id, to_id, item_id)
        resp = {"type": "trade_result", "ok": ok, "reason": reason, "from": from_id, "to": to_id, "item_id": item_id, "request_id": request_id, "ts": now_ms()}
        await self.send(ws, resp)

        if ok:
            await self.broadcast_to_player(from_id, {"type": "inventory_update", "reason": "trade_out", "item_id": item_id, "to": to_id, "ts": now_ms()})
            await self.broadcast_to_player(to_id, {"type": "inventory_update", "reason": "trade_in", "item_id": item_id, "from": from_id, "ts": now_ms()})

    async def handle_trade_batch(self, ws: WebSocketServerProtocol, from_id: str, data: Dict[str, Any]) -> None:
        to_id = str(data.get("to") or "")
        item_ids = data.get("item_ids")
        request_id = data.get("request_id")
        if not to_id or not isinstance(item_ids, list):
            await self.send(ws, {"type": "trade_batch_result", "ok": False, "error": "missing_to_or_item_ids", "request_id": request_id})
            return

        ok, reason, moved, failed = await self.inv.batch_trade(from_id, to_id, item_ids)
        await self.send(ws, {"type": "trade_batch_result", "ok": ok, "reason": reason, "from": from_id, "to": to_id, "moved": moved, "failed": failed, "request_id": request_id, "ts": now_ms()})
        if ok and moved:
            await self.broadcast_to_player(from_id, {"type": "inventory_update", "reason": "trade_batch_out", "moved": moved, "to": to_id, "ts": now_ms()})
            await self.broadcast_to_player(to_id, {"type": "inventory_update", "reason": "trade_batch_in", "moved": moved, "from": from_id, "ts": now_ms()})

    async def handle_whoami(self, ws: WebSocketServerProtocol, player_id: str, data: Dict[str, Any]) -> None:
        p = self.inv.players.get(player_id)
        if not p:
            await self.send(ws, {"type": "whoami", "ok": False, "error": "unknown_player"})
            return
        await self.send(ws, {"type": "whoami", "ok": True, "player_id": p.player_id, "name": p.name, "session_id": p.session_id})

    async def route(self, ws: WebSocketServerProtocol, msg: Dict[str, Any]) -> None:
        mtype = msg.get("type")
        if mtype == "login":
            await self.handle_login(ws, msg)
            return

        async with self._conn_lock:
            player_id = self.connections.get(ws)

        if not player_id:
            await self.send(ws, {"type": "error", "error": "not_logged_in"})
            return

        if mtype == "inventory_get":
            await self.handle_inventory_get(ws, player_id, msg)
        elif mtype == "spawn_item":
            await self.handle_spawn_item(ws, player_id, msg)
        elif mtype == "trade":
            await self.handle_trade(ws, player_id, msg)
        elif mtype == "trade_batch":
            await self.handle_trade_batch(ws, player_id, msg)
        elif mtype == "whoami":
            await self.handle_whoami(ws, player_id, msg)
        else:
            await self.send(ws, {"type": "error", "error": "unknown_message_type", "message_type": mtype})

    async def handler(self, ws: WebSocketServerProtocol):
        await self.send(ws, {"type": "hello", "server_time_ms": now_ms()})
        try:
            async for raw in ws:
                try:
                    msg = json.loads(raw)
                    if not isinstance(msg, dict):
                        await self.send(ws, {"type": "error", "error": "invalid_message"})
                        continue
                except Exception:
                    await self.send(ws, {"type": "error", "error": "invalid_json"})
                    continue
                await self.route(ws, msg)
        except websockets.exceptions.ConnectionClosed:
            pass
        finally:
            async with self._conn_lock:
                player_id = self.connections.pop(ws, None)
            if player_id:
                await self.inv.unbind_ws(player_id, ws)

    async def run(self):
        async with websockets.serve(self.handler, self.host, self.port, max_size=2**20, ping_interval=20, ping_timeout=20):
            logging.info("Server listening on %s:%d", self.host, self.port)
            await asyncio.Future()


def main():
    import argparse

    parser = argparse.ArgumentParser()
    parser.add_argument("--host", default="0.0.0.0")
    parser.add_argument("--port", type=int, default=8765)
    args = parser.parse_args()

    server = GameServer(args.host, args.port)

    async def seed():
        await server.inv.ensure_player("alice", "Alice")
        await server.inv.ensure_player("bob", "Bob")
        await server.inv.create_item_for_player("alice", "gold_coin", {"amount": 100})
        await server.inv.create_item_for_player("alice", "sword", {"rarity": "common"})
        await server.inv.create_item_for_player("bob", "potion", {"heals": 50})

    async def runner():
        await seed()
        await server.run()

    asyncio.run(runner())


if __name__ == "__main__":
    main()